#!/bin/bash
# Common Deployment Script
# Generated by Pattern Miner
# This script automates the common deployment pattern

set -e

# Configuration
DEPLOY_DIR="${DEPLOY_DIR:-/var/www/app}"
BACKUP_DIR="${BACKUP_DIR:-/var/backups/app}"
DATE=$(date +%Y%m%d_%H%M%S)

echo "Starting deployment..."

# Step 1: Pull latest code
echo "Pulling latest code..."
cd /path/to/repo
git pull origin main

# Step 2: Install dependencies
echo "Installing dependencies..."
pip install -r requirements.txt

# Step 3: Run migrations
echo "Running migrations..."
python manage.py migrate

# Step 4: Collect static files
echo "Collecting static files..."
python manage.py collectstatic --noinput

# Step 5: Backup current deployment
echo "Creating backup..."
mkdir -p "$BACKUP_DIR"
cp -r "$DEPLOY_DIR" "$BACKUP_DIR/deployment_$DATE"

# Step 6: Restart services
echo "Restarting services..."
sudo systemctl restart app.service

# Step 7: Health check
echo "Running health check..."
curl -f http://localhost:8000/health || exit 1

echo "Deployment completed successfully!"
